const bulkUserNameBuilder = async (data) => {
  const { jwtUser = null, usersData } = data;

  for (const user of usersData) {
    if (!_.isEmpty(jwtUser) && !_.isEmpty(_.get(jwtUser, "oid", ""))) {
      user.userName = _.trim(getUserNameUsingUserNameOrder({ userData: user }));
    } else {
      let name = "";
      let hasFirstName = false;

      if (user.first_name != undefined && user.first_name != "") {
        name += user.first_name;
        hasFirstName = true;
      }

      if (user.last_name != undefined && user.last_name != "") {
        if (hasFirstName) {
          name += ` `;
        }
        name += user.last_name;
      }
      user.userName = _.trim(name);
    }
  }
};

const getUserNameUsingUserNameOrder = (data) => {
  const { userNameOrder = ["FIRST_NAME", "LAST_NAME"], userData = {} } = data;
  const userNameOrderMap = _.get(data, "userNameOrderMap", {
    FIRST_NAME: "first_name",
    LAST_NAME: "last_name",
    MIDDLE_NAME: "middle_name",
    PRONOUNS: "pronouns",
    SUFFIX: "suffix",
    PREFERRED_NAME: "preferred_name",
  });
  const userNameArray = _.map(userNameOrder, (name) => {
    const baseName = name.replace(/[^a-zA-Z_]/g, "").replace("_INITIAL", "");
    const dbField = _.get(userNameOrderMap, baseName);
    if (dbField) {
      let value = _.get(userData, dbField, "");
      if (!_.isEmpty(value)) {
        if (_.includes(name, "_INITIAL")) {
          value = _.head(value);
        }
        const match = name.match(/^([^a-zA-Z]*)([a-zA-Z_]+)([^a-zA-Z]*)$/);
        if (match) {
          const [, prefix, , suffix] = match;
          value = `${prefix}${value}${suffix}`;
        }
        return value;
      }
    }
    return null;
  });
  return _.join(_.compact(userNameArray), " ");
};

const fetchBehaviourIncidentExportData = async (data) => {
  const { input = {}, jwtUser } = data;
  const { columns = [] } = input;

  //   //   Fetch root categories and convert them to string
  //   const categoryIds = _.filter(
  //     _.map(incidents, "category_id"),
  //     (id) => !_.isNil(id)
  //   ).map((id) => _.toString(id));

  //   console.log("Category IDs:", JSON.stringify(categoryIds));
  const rootCategoryMap = _.keyBy(rootCategories, "sub_category_id");
  console.log("rootCategoryMap:", JSON.stringify(rootCategoryMap));

  // Initialize spreadsheet
  const workbook = new ExcelJS.Workbook();
  const worksheet = workbook.addWorksheet("Conducts");

  // Nomenclature constants
  const incidentName = _.get(
    _.find(nomenclatureTokens, { key: "incident" }),
    "value",
    "Note"
  );
  const levelName = _.get(
    _.find(nomenclatureTokens, { key: "level" }),
    "value",
    "Level"
  );
  const actionName = _.get(
    _.find(nomenclatureTokens, { key: "action" }),
    "value",
    "Action"
  );

  const allColumns = {
    SYSTEM_ID: [{ header: "System ID", key: "id", width: 10, hidden: true }],
    STATUS: [{ header: "Status", key: "state", width: 12 }],
    INCIDENT_ID: [{ header: `${incidentName} ID`, key: "uid", width: 10 }],
    INVOLVED_STUDENT: [
      { header: "Student involved", key: "involvedStudent", width: 20 },
      { header: "Student UID", key: "involvedStudentId", width: 24 },
    ],
    CURRICULUM_AND_GRADE: [
      { header: "Curriculum", key: "curriculum", width: 10 },
      { header: "Grade", key: "grade", width: 15 },
    ],
    TITLE: [{ header: `${incidentName} title`, key: "title", width: 40 }],
    CATEGORY: [
      { header: "Category", key: "rootCategory", width: 20 },
      { header: "Sub-Category", key: "category", width: 40 },
    ],
    LEVEL: [{ header: levelName, key: "severity", width: 10 }],
    LOCATION: [{ header: "Location", key: "location", width: 15 }],
    INCIDENT_TIME: [
      {
        header: `Date and time of ${_.toLower(incidentName)}`,
        key: "incidentTime",
        width: 24,
      },
    ],
    ACTIONS: [{ header: pluralize(actionName), key: "actions", width: 30 }],
    REFERRED_TO: [{ header: "Referred to", key: "referredTo", width: 30 }],
    SHARED_WITH: [
      { header: "Shared with student", key: "sharedWithStudent", width: 20 },
      { header: "Shared with family", key: "sharedWithFamily", width: 20 },
    ],
    LINKED_INCIDENTS: [
      {
        header: `Linked ${pluralize(incidentName)}`,
        key: "linkedIncidents",
        width: 30,
      },
    ],
    CREATED_BY: [
      { header: `${incidentName} created by`, key: "createdBy", width: 20 },
    ],
    CREATED_AT: [
      { header: `${incidentName} created on`, key: "createdAt", width: 24 },
    ],
    UPDATED_BY: [{ header: "Last modified by", key: "updatedBy", width: 20 }],
    UPDATED_AT: [{ header: "Last modified on", key: "updatedAt", width: 24 }],
  };

  const includeAllColumns = _.isEmpty(columns);

  // Add header row
  if (includeAllColumns) {
    worksheet.columns = _.flatten(_.values(allColumns));
  } else {
    const columnsToInclude = [
      ...allColumns.SYSTEM_ID,
      ...allColumns.INCIDENT_ID,
      ...allColumns.STATUS,
      ...allColumns.INVOLVED_STUDENT,
    ];

    // Using _.keys(allColumns) to maintain the order of columns
    _.forEach(_.keys(allColumns), (column) => {
      if (_.includes(columns, column)) {
        columnsToInclude.push(..._.get(allColumns, column, []));
      }
    });

    worksheet.columns = columnsToInclude;
  }

  // Style header
  worksheet.getRow(1).font = { bold: true };

  // Format user names according to their org config
  const nameBuilderUserData = _.map(incidents, "involved_student");
  if (includeAllColumns || _.includes(columns, "CREATED_BY")) {
    nameBuilderUserData.push(..._.map(incidents, "created_by_user"));
  }
  if (includeAllColumns || _.includes(columns, "UPDATED_BY")) {
    nameBuilderUserData.push(..._.map(incidents, "updated_by_user"));
  }
  if (includeAllColumns || _.includes(columns, "REFERRED_TO")) {
    const referredTo = _.flatMap(incidents, (incident) =>
      _.uniqBy(_.get(incident, "referred_to", []), "id")
    );
    nameBuilderUserData.push(...referredTo);
  }
  await bulkUserNameBuilder({
    usersData: nameBuilderUserData,
    jwtUser,
  });

  // Add rows
  _.forEach(incidents, (incident) => {
    const rowData = {
      id: _.get(incident, "id"),
      uid: _.get(incident, "sourced_id"),
      state: _.get(incident, "state"),
      involvedStudent: _.get(incident, "involved_student.userName"),
      involvedStudentId: _.get(incident, "involved_student_id"),
    };

    const columnsToInclude = includeAllColumns ? _.keys(allColumns) : columns;

    _.forEach(columnsToInclude, (column) => {
      switch (column) {
        case "CURRICULUM_AND_GRADE":
          rowData.curriculum = _.get(incident, "curriculum_acronyms");
          rowData.grade = _.get(incident, "grade_names");
          break;
        case "TITLE":
          rowData.title = _.get(incident, "title");
          break;
        case "CATEGORY":
          rowData.category = _.get(incident, "category_name");
          rowData.rootCategory = _.get(
            rootCategoryMap,
            `${_.get(incident, "category_id")}.name`
          );
          break;
        case "LEVEL":
          rowData.severity = _.get(incident, "severity_name");
          break;
        case "LOCATION":
          rowData.location = _.get(incident, "location_name");
          break;
        case "INCIDENT_TIME":
          rowData.incidentTime = moment(
            _.get(incident, "incident_time")
          ).format("Do MMM YYYY, hh:mm A");
          break;
        case "ACTIONS":
          rowData.actions = _.get(incident, "action_titles");
          break;
        case "REFERRED_TO":
          rowData.referredTo = _.map(_.get(incident, "referred_to"), "userName")
            .filter(Boolean)
            .join(", ");
          break;
        case "SHARED_WITH":
          rowData.sharedWithStudent =
            _.get(incident, "accessibility.INVOLVED_STUDENT") === "CAN_VIEW"
              ? "Yes"
              : "No";
          rowData.sharedWithFamily =
            _.get(incident, "accessibility.FAMILY_MEMBERS") === "CAN_VIEW"
              ? "Yes"
              : "No";
          break;
        case "LINKED_INCIDENTS":
          rowData.linkedIncidents = _.get(
            incident,
            "linked_incident_sourced_ids"
          );
          break;
        case "CREATED_BY":
          rowData.createdBy = _.get(incident, "created_by_user.userName");
          break;
        case "CREATED_AT":
          rowData.createdAt = moment(_.get(incident, "created_at")).format(
            "Do MMM YYYY, hh:mm A"
          );
          break;
        case "UPDATED_BY":
          rowData.updatedBy = _.get(incident, "updated_by_user.userName");
          break;
        case "UPDATED_AT":
          rowData.updatedAt = moment(_.get(incident, "updated_at")).format(
            "Do MMM YYYY, hh:mm A"
          );
          break;
      }
    });

    const row = worksheet.addRow(rowData);

    const borderStyle = {
      top: { style: "thin", color: { argb: "DADBDB" } },
      left: { style: "thin", color: { argb: "DADBDB" } },
      bottom: { style: "thin", color: { argb: "DADBDB" } },
      right: { style: "thin", color: { argb: "DADBDB" } },
    };
    const fillStyle = {
      type: "pattern",
      pattern: "solid",
    };

    const statusColor = {
      DRAFT: "FFEBAD",
      PUBLISHED: "E6E3FF",
      RESOLVED: "C1F7EC",
    };
    const statusColumnLetter = worksheet.getColumn("state").letter;
    const statusCell = row.getCell(statusColumnLetter);
    statusCell.border = borderStyle;
    statusCell.fill = {
      ...fillStyle,
      fgColor: { argb: statusColor[_.get(incident, "state")] },
    };

    if (includeAllColumns || _.includes(columns, "CATEGORY")) {
      const categoryColor = _.replace(
        _.get(rootCategoryMap, `${_.get(incident, "category_id")}.color`),
        "#",
        ""
      );

      const rootCategoryColumnLetter =
        worksheet.getColumn("rootCategory").letter;
      const rootCategoryCell = row.getCell(rootCategoryColumnLetter);
      rootCategoryCell.border = borderStyle;
      rootCategoryCell.fill = {
        ...fillStyle,
        fgColor: { argb: categoryColor },
      };
    }

    if (includeAllColumns || _.includes(columns, "LEVEL")) {
      const severityColumnLetter = worksheet.getColumn("severity").letter;
      const severityCell = row.getCell(severityColumnLetter);
      severityCell.border = borderStyle;
      severityCell.fill = {
        ...fillStyle,
        fgColor: {
          argb: _.replace(_.get(incident, "severity_color"), "#", ""),
        },
      };
    }
  });

  // Upload to S3
  const fStream = await workbook.xlsx.writeBuffer();
  // create a xlsx file  and store it in the folder behaviour-incident-exports
  const fileName = `behaviour-incident-export-${moment().format(
    "YYYY-MM-DD"
  )}.xlsx`;
  const filePath = `${fileName}`;
  await fs.promises.writeFile(filePath, fStream);

  //   const url = await uploadBulkDataToS3Sync({
  //     folderName: "behaviour-incident-exports",
  //     fileType: "EXCEL",
  //     fStream,
  //     jwtUser,
  //   });

  //   return { url };
};

